class OptimizedTokenCache:
    """优化的Token缓存，减少重复计算"""
    def __init__(self, tokenizer, max_size=50000):
        self.tokenizer = tokenizer
        self.cache = {}
        self.max_size = max_size
        self.access_times = {}
        self.access_counter = 0
    
    @lru_cache(maxsize=50000)
    def get_token_count(self, text):
        """优化的token计算"""
        return len(self.tokenizer.encode(text))
    
    def batch_token_count(self, texts):
        """批量token计算，减少CPU开销"""
        return [self.get_token_count(text) for text in texts]
    
    def clear_cache(self):
        """清空缓存"""
        self.cache.clear()
        self.access_times.clear()


class MedicalConsultationEnvWithPatientLLMCategorySimple(MedicalConsultationEnv):
    """
    A medical consultation environment where a doctor (policy model) interacts with a patient (fixed LLM).
    The doctor asks questions and makes a diagnosis, while the patient responds based on their condition.
    The patient's responses are generated by an external LLM and passed to the environment.
    """

    _readable_log_initialized = False
    _readable_log_filename = None  # 带时间戳的日志文件名，在首次调用时生成

    @classmethod
    def _append_readable_log(cls, text: str):
        try:
            import os
            from datetime import datetime
            log_dir = os.environ.get("RAGEN_READABLE_LOG_DIR", "logs/readable")
            os.makedirs(log_dir, exist_ok=True)
            
            # 首次调用时生成带时间戳的文件名，并设置到环境变量供 PPO trainer 使用
            if cls._readable_log_filename is None:
                timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
                cls._readable_log_filename = f"med_dialogue_debug_{timestamp}.log"
                # 设置环境变量，让 log_ppo_trajectory 也能使用同一个文件
                os.environ["RAGEN_DEBUG_LOG_FILENAME"] = cls._readable_log_filename
            
            log_file = os.path.join(log_dir, cls._readable_log_filename)

            # 每次程序启动首次调用时初始化日志
            if not cls._readable_log_initialized:
                cls._readable_log_initialized = True
                # 写入日志头部信息
                with open(log_file, "w", encoding="utf-8") as f:
                    f.write(f"[Log Started] {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                    f.write("=" * 80 + "\n")

            # 文件大小控制：如果超过 100MB，就重置文件
            try:
                if os.path.exists(log_file) and os.path.getsize(log_file) > 100 * 1024 * 1024:  # 100MB
                    with open(log_file, "w", encoding="utf-8") as f:
                        f.write(f"[Log Truncated] File size limit (100MB) reached. Resetting log.\n")
            except OSError:
                pass

            ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            with open(log_file, "a", encoding="utf-8") as f:
                f.write(f"[{ts}] pid={os.getpid()}\n")
                f.write(text)
                if not text.endswith("\n"):
                    f.write("\n")
                f.write("=" * 80 + "\n")
        except Exception:
            # 避免因为日志失败影响主流程
            pass
 
