    @staticmethod
    def _get_data_from_parquet(path: str):
        df = pd.read_parquet(path)
        data = []
        for item in df["reward_model"].tolist():
            data.append({
                "target":              item.get("ground_truth") if item.get("ground_truth") is not None else {},
                "patient_information": [],
                "description":         "" if item.get("enhanced_description") is None else str(item.get("enhanced_description")),
                # 新增：从 reward_model 中读取结构化主诉，供环境构造第一轮固定对话使用
                "patient_complaint":   "" if item.get("patient_complaint") is None else str(item.get("patient_complaint")),
                # 保存完整的 reward_model，供 _prepare_patient_prompt 使用
                "reward_model":        item if item is not None else {},
            })
        original_indices = [ei.get("index") for ei in df["extra_info"].tolist()]
        seed_to_index = {orig: i for i, orig in enumerate(original_indices)}
        return data, seed_to_index

